const BLOQUEADOS = ['bet', 'aposta', 'crypto', 'criptomoeda', 'loteria', 'casino', 'cassino', 'jogo online', 'gaming'];

const filtrados = $input.all().filter(item => {
  const seg = (item.json.segmento || '').toLowerCase();
  const nome = (item.json.nome || '').toLowerCase();
  return !BLOQUEADOS.some(b => seg.includes(b) || nome.includes(b));
});

return filtrados;

const lead = $input.first().json;

const instagram = (lead.instagram && typeof lead.instagram === 'object') ? lead.instagram : {};
const hasInstagram = !!(instagram.local_url || instagram.dono_url || instagram.decisor_url);
const fonte = hasInstagram ? 'Instagram' : 'Google Maps';

const dono = lead.dono ? lead.dono.split(' ')[0] : null;
function formatNome(nome) {
  if (!nome) return 'o negócio';
  const tc = nome.toLowerCase().replace(/(?:^|\s)\S/g, c => c.toUpperCase());
  return tc.split(/\s+/).filter(w => w.length > 0).slice(0, 2).join(' ');
}
const lead_nome = formatNome(lead.nome_fantasia || lead.nome);

const segmentoResultadoMap = {
  'hamburgueria': 'pedidos e clientes na loja',
  'restaurante': 'pedidos e clientes na loja',
  'delivery': 'pedidos',
  'pizza': 'pedidos e clientes na loja',
  'clinica': 'agendamentos e pacientes',
  'estetica': 'agendamentos',
  'saude': 'agendamentos e pacientes',
  'odonto': 'agendamentos e pacientes',
  'escola': 'matrículas e alunos',
  'curso': 'matrículas e alunos',
  'aviacao': 'alunos e matrículas',
  'academia': 'alunos',
  'personal': 'alunos',
  'comercio': 'vendas e clientes na loja',
  'loja': 'vendas e clientes na loja',
  'servico': 'novos clientes e agendamentos',
  'advocacia': 'novos clientes',
  'contabil': 'novos clientes'
};

const segLower = (lead.segmento || '').toLowerCase();
let resultado_alvo = lead.resultado_alvo;
if (!resultado_alvo) {
  for (const [key, value] of Object.entries(segmentoResultadoMap)) {
    if (segLower.includes(key)) { resultado_alvo = value; break; }
  }
  resultado_alvo = resultado_alvo || 'novos clientes';
}

const angulo = lead.angulo || 'dor';
const conteudo_angulo = lead.conteudo_angulo || `negócio local no segmento de ${lead.segmento || 'serviços'} que depende de movimento e indicação`;

const contexto = `Gere a abordagem inicial para o seguinte lead:\n- nome_dono: ${dono || ''}\n- nome_negocio: ${lead_nome}\n- segmento: ${lead.segmento || 'não informado'}\n- cidade: ${lead.cidade || 'não informada'}\n- fonte: ${fonte}\n- angulo: ${angulo}\n- conteudo_angulo: ${conteudo_angulo}\n- resultado_alvo: ${resultado_alvo}`;

return [{
  json: {
    lead_id: lead.id,
    lead_nome,
    dono,
    segmento: lead.segmento || '',
    cidade: lead.cidade || '',
    fonte,
    resultado_alvo,
    whatsapp_numero: lead.whatsapp_numero,
    historico_atual: lead.historico_resumido || '',
    contexto_lead: contexto
  }
}];

const agentOutput = $input.first().json.output || '';
const ctx = $('Preparar Contexto').first().json;

const partes = agentOutput.split(/\\/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

const mensagens = ['Oi, tudo bem?', ...partes].slice(0, 3);

return mensagens.map(mensagem => ({
  json: {
    mensagem,
    whatsapp_numero: ctx.whatsapp_numero,
    lead_id: ctx.lead_id,
    agent_output: agentOutput
  }
}));

const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  if (i > 0) await new Promise(r => setTimeout(r, 3000));
  results.push(items[i]);
}
return results;

const agentOutput = $('AGENTE DE ABORDAGEM').first().json.output || '';
const ctx = $('Preparar Contexto').first().json;

const partes = agentOutput.split(/\\/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

const restantes = partes.slice(2);

return restantes.map(mensagem => ({
  json: {
    mensagem,
    whatsapp_numero: ctx.whatsapp_numero,
    lead_id: ctx.lead_id
  }
}));

const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  if (i > 0) await new Promise(r => setTimeout(r, 3000));
  results.push(items[i]);
}
return results;
